import { NextResponse } from 'next/server'
import { writeFile, mkdtemp, rm } from 'fs/promises'
import { join } from 'path'
import { tmpdir } from 'os'
import { exec } from 'child_process'
import { promisify } from 'util'

const execAsync = promisify(exec)

export async function POST(req: Request) {
  try {
    const { code, language, filename } = await req.json()
    
    if (!code) {
      return NextResponse.json({ error: 'Code is required' }, { status: 400 })
    }

    // Determine extension
    let ext = '.txt'
    switch(language) {
      case 'go': ext = '.go'; break;
      case 'python': ext = '.py'; break;
      case 'java': ext = '.java'; break;
      case 'javascript': ext = '.js'; break;
    }

    const tempDir = await mkdtemp(join(tmpdir(), 'spectra-playground-'))
    const tempFile = join(tempDir, filename || `code${ext}`)
    
    await writeFile(tempFile, code)

    try {
      // Execute Spectra. Assuming `spectra` is in PATH. 
      // In a real Vercel environment, we'd need to ship the linux binary.
      const { stdout } = await execAsync(`spectra scan "${tempDir}" --output json --quiet`)
      
      // Cleanup
      await rm(tempDir, { recursive: true, force: true })

      const result = JSON.parse(stdout)
      return NextResponse.json(result)
    } catch (execError: any) {
      // Cleanup on error
      await rm(tempDir, { recursive: true, force: true })
      
      // If spectra returns a non-zero exit code (e.g. found issues), stdout still has the JSON
      if (execError.stdout) {
        try {
          return NextResponse.json(JSON.parse(execError.stdout))
        } catch(e) {
          return NextResponse.json({ error: 'Failed to parse spectra output' }, { status: 500 })
        }
      }
      return NextResponse.json({ error: 'Failed to execute spectra' }, { status: 500 })
    }

  } catch (error) {
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 })
  }
}
